INSERT OR IGNORE INTO [ec_pages] ([id],[slug],[status],[author_id],[primary_byline_id],[created_at],[updated_at],[published_at],[scheduled_at],[deleted_at],[version],[live_revision_id],[draft_revision_id],[locale],[translation_group],[title],[content]) VALUES ('01KP1Y1X17N72PD53X78WWT5MA','about','published',NULL,NULL,'2026-04-12T22:47:31.111Z','2026-04-12T22:47:31.111Z','2026-04-12T22:47:31.111Z',NULL,NULL,1,NULL,NULL,'en','01KP1Y1X17N72PD53X78WWT5MA','About','[{"_type":"block","style":"normal","children":[{"_type":"span","text":"A place for writing about software, design, and the occasional stray thought. No posting schedule, no newsletter funnel. Just things I wanted to write down."}]},{"_type":"block","style":"normal","children":[{"_type":"span","text":"Built with Astro and EmDash. The source is open if you want to see how it works."}]}]');

